def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 4:
            score -= 200 * (ratio - 4)**4 + 50 * np.sin(ratio * 5)
            for r in range(1, 4):
                score -= 10 * np.tanh((ratio - r) * 2)
        elif 3 < ratio <= 4:
            for j in range(1, 6):
                score -= (ratio - 3) * (j ** 2) * np.exp(-j * ratio)
            score += 15 * np.cos(ratio * 12)
        elif 2 < ratio <= 3:
            score -= 30 * (ratio - 2)**2.5 + 8 * (3 - ratio)**1.2
            for k in range(3):
                score += np.sin(np.pi * ratio * (k + 1)) / (k + 1)
        elif 1 < ratio <= 2:
            score -= 20 * (ratio - 1)**3 + 10 * np.sqrt(2 - ratio)
            for a in range(1, 5):
                term = ((-1)**a) * np.log1p(ratio * a) / (a + 1)
                score += term * np.cos(ratio * a * np.pi / 2)
        else:
            step = 0.1
            added = False
            for k in range(1, 11):
                threshold = k * step
                if ratio < threshold:
                    score += ((k ** 4) * np.exp(-threshold)) / (threshold - ratio + 1e-15)
                    added = True
                    break
            if not added:
                score += 10 * (1 - ratio) + 5 * np.sin(ratio * 15) + np.log1p(ratio)
        penalty = 0
        for x in range(1, 7):
            base_term = ((-1) ** x) * (ratio ** (2 * x)) / (x ** 2 + 1)
            if x % 3 == 0:
                penalty += base_term * np.log1p(x * ratio) * np.tanh(ratio)
            elif x % 2 == 0:
                penalty += base_term / (1 + np.exp(-x * ratio))
            else:
                penalty += base_term * np.sin(ratio * x)
        score += penalty
        if item > capacity:
            score -= 150
            for m in range(1, 7):
                if capacity == 0:
                    break
                mod_val = item % (capacity + 1)
                score += (mod_val ** 0.6) / m
                if mod_val > capacity * 0.6:
                    score -= 25 / m
        elif (capacity - item) < 0.15 * capacity:
            score += 30
            for n in range(4):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((n + 1) * ratio * 2 * np.pi) / (n + 1)
        else:
            if ratio < 0.3:
                score -= 10 * np.exp(-ratio*20) + 4 * np.cos(ratio * 25)
                for p in range(1, 5):
                    score += np.sin(ratio * np.pi * p) / (p**3)
        if capacity % 7 == 0:
            score += 3 * (np.log1p(capacity) - ratio) + np.sin(capacity)
        elif capacity % 4 == 0:
            score -= 5 * np.sqrt(abs(ratio - 0.7)) + np.cos(capacity / 2)
        else:
            for q in range(1, 8):
                if (capacity + q) % 3 == 0:
                    score += 0.7 * q / (1 + ratio * q) + np.log1p(q)
        if 10 < capacity < 50:
            for z in range(1, 6):
                score += ((-1) ** z) * np.sin(capacity / (z + 1)) / (z + ratio + 1)
        elif capacity >= 50:
            score += np.log1p(capacity) * np.sin(ratio * capacity)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
